// 현재 페이지를 이미지로 저장하는 JavaScript
try {
    // 현재 페이지 번호 가져오기
    var pageNum = this.pageNum;

    // 파일명 생성 (페이지 번호 포함)
    var fileName = "page_" + (pageNum + 1) + ".png";

    // 저장 대화상자 표시
    var saveParams = {
        cDIPath: fileName,
        cFileSys: "CDOM"
    };

    // 현재 페이지를 이미지로 내보내기
    this.exportAsImage({
        nPage: pageNum,
        cFormat: "png",
        nBitsPerComponent: 8,
        nHDPI: 150,
        nVDPI: 150,
        cFileSys: "CDOM",
        cDIPath: fileName
    });

    app.alert("페이지 " + (pageNum + 1) + "이(가) 이미지로 저장되었습니다!", 3);

} catch (e) {
    app.alert("이미지 저장 중 오류가 발생했습니다: " + e.message, 0);
}

// 드롭다운 선택 시 실행되는 함수
function onSectionSelect() {
    // 선택된 값 가져오기
    var selectedValue = event.value;

    // 빈 값이면 아무것도 하지 않음
    if (selectedValue == "" || selectedValue == "선택하세요") {
        return;
    }

    try {
        // 선택된 값에 따라 다른 영역 복사
        var cropRect;
        var sectionName;

        switch(selectedValue) {
            case "sectionA":
                cropRect = [100, 400, 300, 600];  // 섹션 A 좌표
                sectionName = "섹션 A";
                break;
            case "sectionB":
                cropRect = [320, 400, 520, 600];  // 섹션 B 좌표
                sectionName = "섹션 B";
                break;
            case "sectionC":
                cropRect = [100, 200, 300, 400];  // 섹션 C 좌표
                sectionName = "섹션 C";
                break;
            default:
                app.alert("알 수 없는 선택입니다.", 0);
                return;
        }

        // 2페이지의 특정 영역 좌표 (포인트 단위)
        var sourceRect = this.getPageBox("Crop", 1); // 2페이지 (0부터 시작)

        // 1페이지에 삽입할 위치
        var targetRect = [50, 200, 250, 400];

        // 이전 템플릿 제거 (있다면)
        try {
            this.removeTemplate("Page2Section");
        } catch(e) {
            // 템플릿이 없으면 무시
        }

        // 2페이지를 XObject로 생성
        var pageTemplate = this.addTemplate({
            nPage: 1,  // 2페이지
            cName: "Page2Section"
        });

        // 1페이지에 템플릿 삽입
        this.addWatermarkFromText({
            cText: "",
            nPage: 0,  // 1페이지
            aRect: targetRect,
            cLayer: "Page2Content"
        });

        app.alert(sectionName + " 내용이 1페이지에 복사되었습니다!", 3);

    } catch (e) {
        app.alert("복사 중 오류: " + e.message, 0);
    }
}

// 메인 실행 함수 호출
onSectionSelect();

