// 이전 crop 내용 제거
function clearPreviousCrop() {
    try {
        this.removeWatermarks();
        var templates = ["Page12Area", "CroppedFromPage12", "MovedFromPage12"];
        for (var i = 0; i < templates.length; i++) {
            try {
                this.removeTemplate(templates[i]);
            } catch(e) {}
        }
    } catch (e) {
        console.println("제거 오류: " + e.message);
    }
}

// 12페이지에서 특정 영역 crop 및 삽입
function cropFromPage12(section) {
    try {
        // 고유한 템플릿 이름
        var templateName = "Page12Cropped_" + new Date().getTime();

        // 12페이지의 특정 영역을 워터마크로 삽입
        this.addWatermarkFromFile({
            cDIPath: this.path,              // 현재 PDF
            nSourcePage: 11,                 // 12페이지 (0부터 시작하므로 11)  ⭐ 핵심 변경!
            nStart: 0,                       // 1페이지에 적용
            nEnd: 0,

            // 핵심: 정확한 crop 영역과 대상 위치
            aSourceRect: section.cropRect,   // 12페이지에서 잘라낼 정확한 영역
            aRect: section.targetRect,       // 1페이지에 배치할 위치

            bOnTop: true,                    // 기존 내용 위에 표시
            bOnPrint: true,                  // 인쇄 시에도 표시
            nRotation: 0,                    // 회전 없음
            nScale: 1.0,                     // 원본 크기
            cLayer: "Page12CropLayer"        // 레이어 이름
        });

        // 성공 메시지
        app.alert(section.name + "이(가) 12페이지에서 1페이지로 정확히 복사되었습니다!\n" +
                 "영역: [" + section.cropRect.join(", ") + "]", 3);

    } catch (e) {
        console.println("12페이지 영역 삽입 오류: " + e.message);

        // 대안 방법: 템플릿 사용
        try {
            fallbackPage12Method(section);
        } catch (e2) {
            app.alert("12페이지 Crop 실행 중 오류: " + e2.message, 0);
        }
    }
}

// 12페이지용 대안 방법
function fallbackPage12Method(section) {
    // 12페이지를 템플릿으로 생성
    var templateName = "Page12Template_" + new Date().getTime();

    this.addTemplate({
        nPage: 11,                    // 12페이지 (0부터 시작)
        cName: templateName,
        aRect: section.cropRect       // crop 영역 지정
    });

    // 1페이지에 템플릿 배치
    this.addWatermarkFromText({
        cText: "",
        nPage: 0,                     // 1페이지
        aRect: section.targetRect,
        cLayer: "Page12Template"
    });

    app.alert("12페이지 영역이 템플릿 방식으로 복사되었습니다!", 3);
}

