// 페이지 크기에 맞는 안전한 위치 계산
function calculateSafePosition(pageBox, method) {
    var minX = Math.min(pageBox[0], pageBox[2]);
    var minY = Math.min(pageBox[1], pageBox[3]);
    var maxX = Math.max(pageBox[0], pageBox[2]);
    var maxY = Math.max(pageBox[1], pageBox[3]);

    var width = maxX - minX;
    var height = maxY - minY;

    var targetWidth = 150;  // 고정 크기
    var targetHeight = 100;

    if (method == 1) {
        // 방법 1: 좌상단
        return [minX + 20, maxY - targetHeight - 20, minX + targetWidth + 20, maxY - 20];
    } else {
        // 방법 2: 우상단  
        return [maxX - targetWidth - 20, maxY - targetHeight - 20, maxX - 20, maxY - 20];
    }
}

