 * @return {Folder} Google Drive 폴더 객체입니다.
 */
function getOrCreateFolder(folderName) {
  const folders = DriveApp.getFoldersByName(folderName);
  if (folders.hasNext()) {
    // 폴더가 이미 존재하면 해당 폴더를 반환합니다.
    Logger.log(`'${folderName}' 폴더를 찾았습니다.`);
    return folders.next();
  } else {
    // 폴더가 없으면 새로 생성하고 반환합니다.
    Logger.log(`'${folderName}' 폴더를 찾을 수 없어 새로 생성합니다.`);
    return DriveApp.createFolder(folderName);
  }
}

