/**
 * Google 드라이브의 루트에 'myDB'라는 새 폴더를 생성합니다.
 * 이 함수는 Google Apps Script 편집기에서 직접 실행할 수 있습니다.
 */
function createFolder() {
  try {
    const parentFolderName = "myDB";
    // 생성할 하위 폴더 목록
    const subFolderNames = [
      "myReceipt",
      "myCall",
      "myOutEstimate",
      "myKaTalk",
      "myBRL",
      "myNameCard",
      "myOrder",
      "myCalendar",
      "myTasks",
      "Gmail 첨부파일"
    ];
    let parentFolder;

    // 루트 드라이브에서 해당 이름의 폴더가 이미 있는지 확인합니다.
    const parentFolders = DriveApp.getFoldersByName(parentFolderName);

    if (parentFolders.hasNext()) {
      // 폴더가 이미 존재하는 경우
      parentFolder = parentFolders.next();
      Logger.log(`'${parentFolderName}' 폴더는 이미 존재합니다.`);
    } else {
      // 폴더가 존재하지 않는 경우, 새로 생성합니다.
      parentFolder = DriveApp.createFolder(parentFolderName);
      Logger.log(`'${parentFolderName}' 폴더를 생성했습니다. ID: ${parentFolder.getId()}`);
    }

    // 목록에 있는 각 하위 폴더를 확인하고 생성합니다.
    subFolderNames.forEach(subFolderName => {
      // "myDB" 폴더 내에 해당 하위 폴더가 있는지 확인합니다.
      const subFolders = parentFolder.getFoldersByName(subFolderName);
      let subFolder; // 하위 폴더 객체를 담을 변수

      if (subFolders.hasNext()) {
        // 하위 폴더가 이미 존재하는 경우
        subFolder = subFolders.next(); // 기존 폴더 객체 가져오기
        Logger.log(`'${subFolderName}' 폴더는 '${parentFolderName}' 폴더 내에 이미 존재합니다. ID: ${subFolder.getId()}`);
      } else {
        // 하위 폴더가 존재하지 않는 경우, 새로 생성합니다.
        subFolder = parentFolder.createFolder(subFolderName); // 새 폴더 생성
        Logger.log(`'${subFolderName}' 폴더를 '${parentFolderName}' 폴더 내에 생성했습니다. ID: ${subFolder.getId()}`);
      }
    });

  } catch (e) {
    // 오류 처리
    Logger.log(`폴더 생성 중 오류 발생: ${e}`);
  }
}

