/**
 * 1. INITIALIZATION SCRIPT
 * Creates Folders, Sets up Processing Trigger, and Sets up Model Update Trigger.
 */
function initialSetup() {
  const ui = SpreadsheetApp.getUi();
  const props = PropertiesService.getScriptProperties();

  try {
    // --- A. FOLDER SETUP ---
    // 1. Find/Create Root 'egdesk'
    const root = DriveApp.getRootFolder();
    const parentIter = root.getFoldersByName("egdesk");
    const egdesk = parentIter.hasNext() ? parentIter.next() : root.createFolder("egdesk");

    // 2. Find/Create 'Uploads' Folder
    const upName = "📇 Business Card Uploads (Auto)";
    const upIter = egdesk.getFoldersByName(upName);
    const uploadFolder = upIter.hasNext() ? upIter.next() : egdesk.createFolder(upName);
    props.setProperty(KEYS.UPLOAD_FOLDER_ID, uploadFolder.getId());

    // 3. Find/Create 'Processed' Folder
    const procName = "✅ Processed Cards (Archive)";
    const procIter = egdesk.getFoldersByName(procName);
    const procFolder = procIter.hasNext() ? procIter.next() : egdesk.createFolder(procName);
    props.setProperty(KEYS.PROCESSED_FOLDER_ID, procFolder.getId());


    // --- B. TRIGGER SETUP ---
    // 1. Processing Trigger (Every 5 mins)
    const triggers = ScriptApp.getProjectTriggers();
    if (!triggers.some(t => t.getHandlerFunction() === 'processNewFiles')) {
      ScriptApp.newTrigger('processNewFiles').timeBased().everyMinutes(5).create();
    }

    // 2. Model Maintenance Trigger (Weekly)
    installMaintenanceTrigger();


    // --- C. AI MODEL SETUP ---
    // Attempt to fetch model. If API key is missing, it will warn user but finish setup.
    let currentModel = "Pending API Key";
    if (props.getProperty(KEYS.API_KEY)) {
      currentModel = fetchAndSaveBestModel();
    }

    ui.alert('설정 완료 (Setup Complete)', 
      `1. 폴더 위치: egdesk/${upName}\n` +
      `2. AI 모델: ${currentModel}\n` + 
      `3. 유지보수: 매주 월요일 최신 모델 자동 확인`, 
      ui.ButtonSet.OK);

  } catch (e) {
    ui.alert('Error', e.toString(), ui.ButtonSet.OK);
  }
}

/**
 * Installs a weekly trigger to update the model version
 */
function installMaintenanceTrigger() {
  const triggers = ScriptApp.getProjectTriggers();
  for (const t of triggers) {
    if (t.getHandlerFunction() === 'fetchAndSaveBestModel') return;
  }

  ScriptApp.newTrigger('fetchAndSaveBestModel')
    .timeBased()
    .everyWeeks(1)
    .onWeekDay(ScriptApp.WeekDay.MONDAY)
    .atHour(9) // Update at 9 AM Monday
    .create();

  console.log("📅 Weekly model update trigger installed.");
}

/**
 * Manual trigger from menu to update model immediately
 */
function manualModelUpdate() {
  const model = fetchAndSaveBestModel();
  SpreadsheetApp.getUi().alert(`AI Model Updated: ${model}`);
}

